VALUES ('tsp-loop-591', 591, 'Route reconstruction', 'CLOSED', 'tsp-rule-route-reconstruction', 'Route reconstruction', 'Reconstructed stop-a -> stop-b -> stop-c -> stop-d -> stop-e -> stop-a at cost 14; CandidateUsedAsAntecedent=false and the supplied route is comparison-only.', 'Derive route-class and branch-elimination metrics from the reconstructed result.', 'Starting at the depot with deterministic orientation, project five ordered reconstruction steps from the inferred edge set with CandidateUsedAsAntecedent=false.', 'Gridville has a certified cycle edge set, but the only ordered route rows are supplied candidates.', 'Reconstructed stop-a -> stop-b -> stop-c -> stop-d -> stop-e -> stop-a at cost 14; CandidateUsedAsAntecedent=false and the supplied route is comparison-only.', 'CLOSED') ON CONFLICT (tsp_loop_id) DO UPDATE SET loop_order = EXCLUDED.loop_order, display_name = EXCLUDED.display_name, status = EXCLUDED.status, primary_inference_rule = EXCLUDED.primary_inference_rule, new_concept = EXCLUDED.new_concept, witness_summary = EXCLUDED.witness_summary, next_frontier = EXCLUDED.next_frontier, planned_closure_criterion = EXCLUDED.planned_closure_criterion, before_state = EXCLUDED.before_state, after_state = EXCLUDED.after_state, completion_disposition = EXCLUDED.completion_disposition;

