VALUES ('check-reference-route', 'Reference route validates and matches the certified finite-instance lower bound', 'tour-reference-ring', TRUE, TRUE, 14) ON CONFLICT (tsp_invariant_check_id) DO UPDATE SET display_name = EXCLUDED.display_name, candidate_tour = EXCLUDED.candidate_tour, expected_hamiltonian_cycle_witness = EXCLUDED.expected_hamiltonian_cycle_witness, expected_optimality_proved = EXCLUDED.expected_optimality_proved, expected_total_travel_cost = EXCLUDED.expected_total_travel_cost;

